import React, { useEffect, useRef } from 'react';

function AnimatedBackground() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let animationFrameId;
    let time = 0;

    const config = {
      particleCount: 80,
      sphereRadius: Math.min(window.innerWidth, window.innerHeight) * 0.25,
      rotationSpeed: 0.003,
      particleSize: 2.5,
      connectionDistance: 80,
      colors: {
        primary: '#10b981',
        secondary: '#06b6d4',
        tertiary: '#3b82f6',
        background: '#ffffff'
      }
    };

    let particles = [];

    const resizeCanvas = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      config.sphereRadius = Math.min(window.innerWidth, window.innerHeight) * 0.22;
      initParticles();
    };

    const initParticles = () => {
      particles = [];
      for (let i = 0; i < config.particleCount; i++) {
        const phi = Math.acos(1 - 2 * (i + 0.5) / config.particleCount);
        const theta = Math.PI * (1 + Math.sqrt(5)) * i;
        particles.push({
          phi, theta,
          size: config.particleSize * (0.5 + Math.random() * 0.5),
          colorIndex: Math.floor(Math.random() * 3),
          pulseOffset: Math.random() * Math.PI * 2
        });
      }
    };

    const project = (x, y, z) => {
      const perspective = 800;
      const scale = perspective / (perspective + z);
      return {
        x: canvas.width / 2 + x * scale,
        y: canvas.height / 2 + y * scale,
        scale
      };
    };

    const getColor = (index, alpha = 1) => {
      const colors = [config.colors.primary, config.colors.secondary, config.colors.tertiary];
      const color = colors[index % 3];
      const r = parseInt(color.slice(1, 3), 16);
      const g = parseInt(color.slice(3, 5), 16);
      const b = parseInt(color.slice(5, 7), 16);
      return `rgba(${r}, ${g}, ${b}, ${alpha})`;
    };

    const animate = () => {
      time += config.rotationSpeed;

      ctx.fillStyle = config.colors.background;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      const gradient = ctx.createRadialGradient(
        canvas.width / 2, canvas.height / 2, 0,
        canvas.width / 2, canvas.height / 2, config.sphereRadius * 2
      );
      gradient.addColorStop(0, 'rgba(16, 185, 129, 0.03)');
      gradient.addColorStop(0.5, 'rgba(6, 182, 212, 0.02)');
      gradient.addColorStop(1, 'rgba(255, 255, 255, 0)');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      const positions3D = particles.map((p, i) => {
        const phi = p.phi;
        const theta = p.theta + time;
        const floatOffset = Math.sin(time * 2 + p.pulseOffset) * 5;
        const radius = config.sphereRadius + floatOffset;
        const x = radius * Math.sin(phi) * Math.cos(theta);
        const y = radius * Math.sin(phi) * Math.sin(theta);
        const z = radius * Math.cos(phi);
        return { x, y, z, particle: p, index: i };
      });

      positions3D.sort((a, b) => a.z - b.z);

      ctx.lineWidth = 0.5;
      for (let i = 0; i < positions3D.length; i++) {
        const p1 = positions3D[i];
        const proj1 = project(p1.x, p1.y, p1.z);
        for (let j = i + 1; j < positions3D.length; j++) {
          const p2 = positions3D[j];
          const dx = p1.x - p2.x;
          const dy = p1.y - p2.y;
          const dz = p1.z - p2.z;
          const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);
          if (dist < config.connectionDistance) {
            const proj2 = project(p2.x, p2.y, p2.z);
            const alpha = (1 - dist / config.connectionDistance) * 0.15 * Math.min(proj1.scale, proj2.scale);
            ctx.beginPath();
            ctx.strokeStyle = getColor(p1.particle.colorIndex, alpha);
            ctx.moveTo(proj1.x, proj1.y);
            ctx.lineTo(proj2.x, proj2.y);
            ctx.stroke();
          }
        }
      }

      positions3D.forEach(({ x, y, z, particle }) => {
        const { x: px, y: py, scale } = project(x, y, z);
        const pulse = 1 + Math.sin(time * 3 + particle.pulseOffset) * 0.2;
        const size = particle.size * scale * pulse;
        const depthAlpha = 0.3 + (scale - 0.5) * 1.4;

        const glowGradient = ctx.createRadialGradient(px, py, 0, px, py, size * 3);
        glowGradient.addColorStop(0, getColor(particle.colorIndex, depthAlpha * 0.3));
        glowGradient.addColorStop(1, getColor(particle.colorIndex, 0));
        ctx.fillStyle = glowGradient;
        ctx.beginPath();
        ctx.arc(px, py, size * 3, 0, Math.PI * 2);
        ctx.fill();

        ctx.fillStyle = getColor(particle.colorIndex, depthAlpha);
        ctx.beginPath();
        ctx.arc(px, py, size, 0, Math.PI * 2);
        ctx.fill();
      });

      animationFrameId = requestAnimationFrame(animate);
    };

    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);
    animate();

    return () => {
      window.removeEventListener('resize', resizeCanvas);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      id="sphere-canvas"
      className="fixed inset-0 z-0 pointer-events-none"
    />
  );
}

export default AnimatedBackground;
